import{f as a,ab as t,p as o,t as r}from"./chunks/framework.A6r4HTKL.js";const p=JSON.parse('{"title":"OS Upgrade","description":"This page lists frequently asked questions related to the 2026 OS upgrade of labs to new Ubuntu release.","frontmatter":{"title":"OS Upgrade","category":"FAQ","permalink":"/do-science/faq/os-upgrade/","outline":1,"description":"This page lists frequently asked questions related to the 2026 OS upgrade of labs to new Ubuntu release."},"headers":[],"relativePath":"do-science/faq/os-upgrade.md","filePath":"do-science/faq/os-upgrade.md"}'),n={name:"do-science/faq/os-upgrade.md"};function i(l,e,s,h,d,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="faq-on-os-upgrades" tabindex="-1">FAQ on OS upgrades <a class="header-anchor" href="#faq-on-os-upgrades" aria-label="Permalink to &quot;FAQ on OS upgrades&quot;">​</a></h1><p><strong>This page lists frequently asked questions related to the OS Upgrades of labs to new Ubuntu release in 2026. <a href="/contact">Contact us</a> with questions to help us grow this FAQ.</strong></p><nav class="table-of-contents"><ul><li><a href="#general">General</a><ul><li><a href="#why-do-we-need-to-upgrade">Why do we need to upgrade?</a></li></ul></li><li><a href="#what-is-the-current-target-version">What is the current target version?</a></li><li><a href="#when-will-you-do-the-upgrade">When will you do the upgrade?</a></li><li><a href="#will-my-running-jobs-be-affected">Will my running jobs be affected?</a></li><li><a href="#will-i-be-notified">Will I be notified?</a></li><li><a href="#will-the-upgrade-affect-my-tools">Will the upgrade affect my tools?</a><ul><li><a href="#workbench">Workbench</a></li><li><a href="#python">Python</a></li><li><a href="#r-rstudio">R / Rstudio</a></li><li><a href="#conda">Conda</a></li><li><a href="#matlab">Matlab</a></li><li><a href="#stata">Stata</a></li></ul></li></ul></nav><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="why-do-we-need-to-upgrade" tabindex="-1">Why do we need to upgrade? <a class="header-anchor" href="#why-do-we-need-to-upgrade" aria-label="Permalink to &quot;Why do we need to upgrade?&quot;">​</a></h3><p>We need to upgrade operating systems on your entry and home machines every other year or so to ensure that your lab runs reliably. OS upgrades are required for continuous security updates and to maintain a basic set of applications in your lab.</p><h2 id="what-is-the-current-target-version" tabindex="-1">What is the current target version? <a class="header-anchor" href="#what-is-the-current-target-version" aria-label="Permalink to &quot;What is the current target version?&quot;">​</a></h2><p>This time we will upgrade Ubuntu operating systems on entry and home machines that run on Ubuntu 22.04 LTS to version 24.04 LTS.</p><h2 id="when-will-you-do-the-upgrade" tabindex="-1">When will you do the upgrade? <a class="header-anchor" href="#when-will-you-do-the-upgrade" aria-label="Permalink to &quot;When will you do the upgrade?&quot;">​</a></h2><p>We expect this upgrade cycle to run during July.</p><h2 id="will-my-running-jobs-be-affected" tabindex="-1">Will my running jobs be affected? <a class="header-anchor" href="#will-my-running-jobs-be-affected" aria-label="Permalink to &quot;Will my running jobs be affected?&quot;">​</a></h2><p>Yes. We need to restart your home machines and all running jobs on this machine will be stopped during upgrades. Jobs running on IAAS, Spot, or GPU machines will not be affected.</p><h2 id="will-i-be-notified" tabindex="-1">Will I be notified? <a class="header-anchor" href="#will-i-be-notified" aria-label="Permalink to &quot;Will I be notified?&quot;">​</a></h2><p>Yes. We will reach out to your lab to schedule the upgrade.</p><h2 id="will-the-upgrade-affect-my-tools" tabindex="-1">Will the upgrade affect my tools? <a class="header-anchor" href="#will-the-upgrade-affect-my-tools" aria-label="Permalink to &quot;Will the upgrade affect my tools?&quot;">​</a></h2><p>Maybe. Below is a description of expected changes in packages that may cause potential effects on your workflows.</p><h3 id="workbench" tabindex="-1">Workbench <a class="header-anchor" href="#workbench" aria-label="Permalink to &quot;Workbench&quot;">​</a></h3><p>OS Upgrade should not affect your Workbench tooling.</p><h3 id="python" tabindex="-1">Python <a class="header-anchor" href="#python" aria-label="Permalink to &quot;Python&quot;">​</a></h3><p>System python version may change. We will specify such changes on these pages prior to each cycle. You may need to reinstall some of your Pip packages.</p><h3 id="r-rstudio" tabindex="-1">R / Rstudio <a class="header-anchor" href="#r-rstudio" aria-label="Permalink to &quot;R / Rstudio&quot;">​</a></h3><p>R version can change slightly, although the main version will remain the same. This should minimize any risk of affecting your scripts. Be aware that the operating system upgrade also upgrade system packages that your R-packages may depend on.</p><h3 id="conda" tabindex="-1">Conda <a class="header-anchor" href="#conda" aria-label="Permalink to &quot;Conda&quot;">​</a></h3><p>No changes expected. Those who use Conda to run Python, R, or other tools should not see any changes.</p><h3 id="matlab" tabindex="-1">Matlab <a class="header-anchor" href="#matlab" aria-label="Permalink to &quot;Matlab&quot;">​</a></h3><p>No changes expected.</p><h3 id="stata" tabindex="-1">Stata <a class="header-anchor" href="#stata" aria-label="Permalink to &quot;Stata&quot;">​</a></h3><p>No changes expected.</p>',28)])])}const f=a(n,[["render",i]]);export{p as __pageData,f as default};
